<template><div class="page"><header class="page-head"><div><h1>Calendrier</h1><p>Sorties du {{ periodLabel }}</p></div><div class="actions"><button class="icon-button" title="Mois precedent" @click="move(-1)"><ChevronLeft/></button><button class="secondary" @click="today">Aujourd'hui</button><button class="icon-button" title="Mois suivant" @click="move(1)"><ChevronRight/></button><button class="icon-button" :disabled="loading" title="Actualiser" @click="load"><RefreshCw :class="{spin:loading}"/></button></div></header><div class="toolbar wrap"><input v-model="search" class="search" type="search" placeholder="Filtrer les titres"><select v-model="type"><option value="">Films et series</option><option value="movie">Films</option><option value="episode">Series</option></select><label class="check"><input v-model="tracked" type="checkbox" @change="load"> Suivis uniquement</label></div><p v-if="error" class="notice error-text">{{ error }}</p><section v-for="group in grouped" :key="group.date" class="calendar-day"><h2>{{ longDate(group.date) }}</h2><div class="calendar-events"><article v-for="event in group.events" :key="`${event.instance}:${event.date}:${event.title}:${event.subtitle}`" class="calendar-event"><img v-if="event.poster_url" :src="event.poster_url" alt=""><div><strong>{{ event.title }}</strong><span>{{ event.subtitle }} · {{ event.instance }}</span></div><span class="badge" :class="event.has_file?'available':event.tracked?'pending':''">{{ event.has_file?'Disponible':event.tracked?'Suivi':'Catalogue' }}</span></article></div></section><p v-if="!loading&&!grouped.length" class="empty">Aucune sortie sur cette periode.</p></div></template>
<script setup>import { computed,onMounted,ref } from 'vue';import { ChevronLeft,ChevronRight,RefreshCw } from '@lucide/vue';import { api } from '@/api';const events=ref([]),search=ref(''),type=ref(''),tracked=ref(false),loading=ref(false),error=ref(''),cursor=ref(new Date());const bounds=computed(()=>{const y=cursor.value.getFullYear(),m=cursor.value.getMonth();return {start:new Date(y,m,1),end:new Date(y,m+1,1)}});const periodLabel=computed(()=>new Intl.DateTimeFormat('fr-FR',{month:'long',year:'numeric'}).format(cursor.value));const filtered=computed(()=>events.value.filter(e=>(!search.value||e.title.toLowerCase().includes(search.value.toLowerCase()))&&(!type.value||e.type===type.value)));const grouped=computed(()=>{const map=new Map();filtered.value.forEach(e=>{const key=e.date.slice(0,10);if(!map.has(key))map.set(key,[]);map.get(key).push(e)});return [...map].map(([date,items])=>({date,events:items}))});function localIso(d){return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`}function longDate(v){return new Intl.DateTimeFormat('fr-FR',{weekday:'long',day:'numeric',month:'long'}).format(new Date(`${v}T12:00:00`))}async function load(){loading.value=true;error.value='';try{events.value=await api(`/api/calendar?start=${localIso(bounds.value.start)}&end=${localIso(bounds.value.end)}&tracked_only=${tracked.value}`)}catch(e){error.value=e.message}finally{loading.value=false}}function move(delta){cursor.value=new Date(cursor.value.getFullYear(),cursor.value.getMonth()+delta,1);load()}function today(){cursor.value=new Date();load()}onMounted(load);</script>
